import React, { memo, useMemo } from 'react';
import styles from './grid.module.less';

const BgRect = memo(({
  className = '',
  children,
  wrapClassName = '',
  // flex,
  type = 'white',
  onClick,
  filter
}) => {
  return (
    <div className={`${styles['bg-rect']} ${type ? styles[type] : ''} ${wrapClassName}`} onClick={onClick}>
      <div className={`${styles['br-cont']}`}>
        <div className={`${styles['br-cont-inner']} ${className}`}>{children}</div>
      </div>
      <div className={`${styles['br-bg']}`}></div>
      {filter && <div className={styles['filter']}></div>}
    </div>
  )
});

export default BgRect;